(function($) {
    "use strict";

    var Typeahead = function(element, options) {
        this.$element = $(element);
        this.options = $.extend({}, Typeahead.defaults, options);
        this.matcher = this.options.matcher || this.matcher;
        this.sorter = this.options.sorter || this.sorter;
        this.select = this.options.select || this.select;
        this.autoSelect = this.options.autoSelect !== undefined ? this.options.autoSelect : true;
        this.source = this.options.source || [];
        this.delay = this.options.delay || 300;
        this.shown = false;
        this.$menu = $(this.options.menu || '<ul class="typeahead dropdown-menu" role="listbox"></ul>');
        this.listen();
    };

    Typeahead.prototype = {
        constructor: Typeahead,

        setSource: function(source) {
            this.source = source;
        },

        lookup: function(query) {
            this.query = query || this.$element.val();
            if (this.query.length < this.options.minLength) {
                return this.shown ? this.hide() : null;
            }
            var self = this;
            setTimeout(function() {
                if ($.isFunction(self.source)) {
                    self.source(self.query, $.proxy(self.process, self));
                } else {
                    self.process(self.source);
                }
            }, this.delay);
        },

        process: function(items) {
            var filteredItems = $.grep(items, this.matcher);
            filteredItems = this.sorter(filteredItems);
            if (filteredItems.length) {
                this.render(filteredItems).show();
            } else {
                this.hide();
            }
        },

        matcher: function(item) {
            return item.toLowerCase().indexOf(this.query.toLowerCase()) !== -1;
        },

        sorter: function(items) {
            return items;
        },

        render: function(items) {
            var self = this;
            var html = items.map(function(item) {
                return '<li><a href="#" role="option">' + item + '</a></li>';
            }).join('');
            this.$menu.html(html);
            this.$menu.find('a').on('click', function(e) {
                e.preventDefault();
                self.select($(this).text());
            });
            this.$element.after(this.$menu);
            return this;
        },

        select: function(item) {
            this.$element.val(item);
            this.hide();
            this.options.afterSelect(item);
        },

        show: function() {
            if (this.shown) return;
            this.$menu.show();
            this.shown = true;
        },

        hide: function() {
            this.$menu.hide();
            this.shown = false;
        },

        listen: function() {
            this.$element.on('focus', $.proxy(this.focus, this))
                         .on('blur', $.proxy(this.blur, this))
                         .on('input', $.proxy(this.input, this));
        },

        focus: function() {
            this.lookup();
        },

        blur: function() {
            this.hide();
        },

        input: function() {
            this.lookup();
        }
    };

    Typeahead.defaults = {
        source: [],
        minLength: 1,
        delay: 300,
        afterSelect: function(item) { console.log('Selected:', item); },
        menu: '<ul class="typeahead dropdown-menu" role="listbox"></ul>'
    };

    $.fn.typeahead = function(options) {
        return this.each(function() {
            var $this = $(this);
            var data = $this.data('typeahead');
            if (!data) {
                $this.data('typeahead', (data = new Typeahead(this, options)));
            }
            if (typeof options === 'string') {
                data[options]();
            }
        });
    };

})(jQuery);
